From 08334293f8883c2bcbb74ed10b8133672fee8706 Mon Sep 17 00:00:00 2001
From: Remi Collet <remi@php.net>
Date: Fri, 6 Jun 2014 14:16:04 +0200
Subject: [PATCH] Fix bug #67390 insecure temporary file use in the configure
 script


diff --git a/acinclude.m4 b/acinclude.m4
index ddf72857839..2681b79f643 100644
--- a/acinclude.m4
+++ b/acinclude.m4
@@ -1700,7 +1700,7 @@ int main(int argc, char *argv[])
 {
   FILE *fp;
   long position;
-  char *filename = "/tmp/phpglibccheck";
+  char *filename = tmpnam(NULL);

   fp = fopen(filename, "w");
   if (fp == NULL) {
-- 
2.34.1

Code statements:
char *filename = "/tmp/phpglibccheck";
fp = fopen(filename, "w");

Code statements:
char *filename = "/tmp/phpglibccheck";
fp = fopen(filename, "w");
